const livesNextGeneration = (isAlive: boolean, neighbors: number): boolean =>
  isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3;

const neighborsOf = ([x, y]: Cell): Cell[] => [
  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
  [x - 1, y    ],             [x + 1, y    ],
  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
];

const countLiveNeighbors = (cells: readonly Cell[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const cell of cells) {
    for (const [nx, ny] of neighborsOf(cell)) {
      const k = key(nx, ny);
      counts.set(k, (counts.get(k) ?? 0) + 1);
    }
  }
  return counts;
};

export function nextGeneration(cells: readonly Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => key(x, y)));
  const next: Cell[] = [];
  for (const [k, count] of countLiveNeighbors(cells)) {
    if (livesNextGeneration(alive.has(k), count)) {
      next.push(parseKey(k));
    }
  }
  return next;
}
